@Component({
  selector: 'hb-message-actions',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    '[attr.data-slot]': "'message-actions'",
  },
  exportAs: 'hbMessageActions',
})
export class HbMessageActionsComponent {
  readonly class = input<ClassValue>('');

  protected readonly classes = computed(() =>
    cn(
      'flex items-center gap-1 group-data-[align=end]/message:flex-row-reverse',
      this.class(),
    ),
  );
}

